(()=>{
'use strict';
const config=window.COLLECTVERSE_SUPABASE||{};
const configured=Boolean(config.url&&config.anonKey&&!config.url.includes('YOUR_PROJECT')&&!config.anonKey.includes('YOUR_'));
const supabase=configured&&window.supabase?.createClient?window.supabase.createClient(config.url,config.anonKey,{auth:{persistSession:true,autoRefreshToken:true,detectSessionInUrl:true}}):null;
const state={session:null,profile:null,cards:[],sets:[],inventory:[],packs:[],packStatus:null,upgrades:[],playerUpgrades:[],badges:[],notes:[],scoreboard:[],listings:[],trades:[],tradeReserved:[],watchlist:[],notifications:[],selectedPlayer:null,pendingClicks:0,busy:false,clickPower:1,eps:0,channels:[]};
const $=id=>document.getElementById(id);
const q=(selector,root=document)=>root.querySelector(selector);
const qa=(selector,root=document)=>[...root.querySelectorAll(selector)];
const fmt=value=>new Intl.NumberFormat('tr-TR',{maximumFractionDigits:1}).format(Number(value)||0);
const safe=value=>String(value??'').replace(/[&<>'"]/g,char=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[char]));
const initials=value=>String(value||'CV').trim().slice(0,2).toUpperCase();
const rarityNames={common:'Common',uncommon:'Uncommon',rare:'Rare',epic:'Epic',legendary:'Legendary',mythic:'Mythic',secret:'Secret'};
const variantMultipliers={Standard:1,Foil:1.5,'Gold Foil':2.5,'Black Edition':3,'Rainbow Holo':4,Animated:5,'Founder Edition':6,'Beta Edition':4};
const pageMeta={home:['OYUNCU MERKEZİ','Ana merkez'],collection:['KART ARŞİVİ','Koleksiyon'],market:['OYUNCU EKONOMİSİ','Pazar'],watchlist:['FİYAT TAKİBİ','İzleme listesi'],trades:['DOĞRUDAN TAKAS','Takas'],scoreboard:['GLOBAL LİDERLİK','Sıralama'],profile:['OYUNCU KİMLİĞİ','Profil'],player:['OYUNCU VİTRİNİ','Oyuncu profili'],news:['GÜNCELLEMELER','Yama notları']};
const errorMessages={AUTH_REQUIRED:'Oturumun sona erdi. Lütfen yeniden giriş yap.',NOT_ENOUGH_ENERGY:'Bu işlem için yeterli enerjin yok.',NOT_ENOUGH_GOLD:'Bu işlem için yeterli Gold bakiyen yok.',DAILY_ALREADY_CLAIMED:'Günlük paketini bugün zaten açtın.',CARD_SOLD_OUT:'Bu kartın kullanılabilir stoğu tükendi.',NO_AVAILABLE_CARDS:'Bu paket için şu anda açılabilir kart bulunmuyor.',CARD_SELECTION_FAILED:'Paket kartı seçilemedi. Lütfen tekrar dene.',LISTING_UNAVAILABLE:'Bu ilan satılmış, iptal edilmiş veya süresi dolmuş.',OWN_LISTING:'Kendi ilanını satın alamazsın.',CARD_LISTED:'Bu kart zaten pazarda listeleniyor.',CARD_OWNERSHIP_CHANGED:'Kartın sahibi değişti. Listeyi yenileyip tekrar dene.',INVALID_PRICE:'Fiyat 1 Gold veya daha fazla olmalı.',BID_TOO_LOW:'Teklifin mevcut tekliften daha yüksek olmalı.',AUCTION_UNAVAILABLE:'Bu açık artırma artık kullanılamıyor.',AUCTION_ENDED:'Açık artırma sona erdi.',AUCTION_HAS_BIDS:'Teklif verilmiş açık artırma iptal edilemez.',RATE_LIMITED:'Çok hızlı işlem yaptın. Birkaç saniye bekleyip tekrar dene.',CARD_RESERVED_FOR_TRADE:'Bu kart bekleyen bir takas teklifinde kullanılıyor.',TRADE_UNAVAILABLE:'Takas teklifi tamamlanmış, iptal edilmiş veya artık kullanılamıyor.',TRADE_EXPIRED:'Takas teklifinin süresi doldu.',TRADE_NOT_RECIPIENT:'Bu takası yalnızca teklifin alıcısı kabul edebilir.',TRADE_NOT_ENOUGH_GOLD:'Takas için taraflardan birinin Gold bakiyesi yetersiz.',TRADE_OWNERSHIP_CHANGED:'Takastaki kartlardan birinin sahibi değişmiş.',TRADE_RESERVATION_LOST:'Takastaki kartlardan biri artık rezerve değil. Teklifi yenile.',INVALID_TRADE_RECIPIENT:'Geçerli bir takas oyuncusu seçmelisin.',EMPTY_TRADE:'Takasa en az bir kart veya Gold eklemelisin.',OFFERED_CARD_NOT_OWNED:'Teklif ettiğin kartlardan biri artık sende değil.',REQUESTED_CARD_NOT_OWNED:'İstediğin kartlardan biri artık karşı oyuncuda değil.',NOT_ENOUGH_FUSION_COPIES:'Birleştirme için yeterli ve kullanılabilir kart kopyası yok.',VARIANT_NOT_FUSIBLE:'Bu varyant daha fazla yükseltilemiyor.',NOT_ADMIN:'Bu işlem için yönetici yetkisi gerekiyor.'};

function notify(message,type='info'){const el=$('toast');el.textContent=message;el.className=`toast show ${type}`;clearTimeout(notify.timer);notify.timer=setTimeout(()=>el.className='toast',3200)}
function report(error){console.error(error);const message=String(error?.message||error||'Bir hata oluştu.');const known=Object.entries(errorMessages).find(([code])=>message.includes(code));const fallback=/failed to fetch|network|timeout/i.test(message)?'Sunucuya ulaşılamadı. Bağlantını kontrol edip tekrar dene.':'İşlem tamamlanamadı. Lütfen tekrar dene.';notify(known?.[1]||fallback,'error')}
function setLoading(button,label='İşleniyor…'){if(!button)return()=>{};const html=button.innerHTML;const disabled=button.disabled;button.disabled=true;button.classList.add('is-loading');button.innerHTML=`<span class="button-spinner" aria-hidden="true"></span>${safe(label)}`;return()=>{if(!button.isConnected)return;button.disabled=disabled;button.classList.remove('is-loading');button.innerHTML=html}}
function isNewCard(cardId,inventory=state.inventory){const limit=Date.now()-86400000;return inventory.some(copy=>copy.card_id===cardId&&new Date(copy.obtained_at).getTime()>=limit)}
function hideBootSplash(){document.documentElement.classList.add('app-ready');$('bootSplash')?.remove()}
function levelInfo(total=state.profile?.total_energy){const value=Number(total)||0;const level=Math.floor(Math.sqrt(value/250))+1;const start=(level-1)**2*250;const end=level**2*250;return{level,current:value-start,needed:end-start,percent:Math.min(100,(value-start)/(end-start)*100)}}
function capacity(){return levelInfo().level*1000}
function owned(cardId,inventory=state.inventory){return inventory.filter(item=>item.card_id===cardId).length}
function collectionScore(inventory=state.inventory){return inventory.reduce((sum,item)=>sum+Number(state.cards.find(card=>card.id===item.card_id)?.score||0)*Number(variantMultipliers[item.variant]||1),0)}
function cardSet(card){return card.card_sets?.name||state.sets.find(set=>set.id===card.set_id)?.name||'CollectVerse'}

function routeTo(route){if(!pageMeta[route])route='home';qa('.page').forEach(page=>page.classList.toggle('active',page.id===`${route}Page`));qa('[data-route]').forEach(button=>button.classList.toggle('active',button.dataset.route===route));$('pageEyebrow').textContent=pageMeta[route][0];$('pageTitle').textContent=pageMeta[route][1];document.querySelector('.app')?.classList.remove('menu-open');history.replaceState(null,'',`#${route}`);if(route==='collection')renderCollection();if(route==='market'||route==='watchlist')loadMarket().catch(report);if(route==='trades')loadTrades().catch(report);if(route==='scoreboard')loadScoreboard().catch(report);if(route==='profile')renderProfile();if(route==='news')renderNews();window.scrollTo({top:0})}
function setAuthTab(tab){$('authLoginMode').checked=tab==='login';$('authRegisterMode').checked=tab==='register';$('authTitle').textContent=tab==='login'?'Tekrar hoş geldin':'Yeni bir koleksiyon kur';$('authSubtitle').textContent=tab==='login'?'Koleksiyonuna kaldığın yerden devam et.':'İlk kartına yalnızca birkaç adım kaldı.'}

async function register(event){event.preventDefault();if(!supabase)return notify('Önce Supabase yapılandırmasını tamamla.','error');const username=$('registerUsername').value.trim();if(!/^[a-zA-Z0-9_ğüşöçıİĞÜŞÖÇ-]{3,20}$/.test(username))return notify('Oyuncu adı 3–20 karakter olmalı.','error');const {error}=await supabase.auth.signUp({email:$('registerEmail').value.trim(),password:$('registerPassword').value,options:{data:{username}}});if(error)return report(error);notify('Hesap oluşturuldu. E-posta kutunu kontrol et.');setAuthTab('login')}
async function login(event){event.preventDefault();if(!supabase)return notify('Önce Supabase yapılandırmasını tamamla.','error');const {error}=await supabase.auth.signInWithPassword({email:$('loginEmail').value.trim(),password:$('loginPassword').value});if(error)report(error)}
async function logout(){await flushClicks();await supabase?.auth.signOut()}

async function loadGame(){const userId=state.session.user.id;const queries=[supabase.rpc('sync_energy'),supabase.from('cards').select('*,card_sets(name,slug)').eq('is_active',true).order('code'),supabase.from('card_sets').select('*').eq('is_active',true).order('name'),supabase.from('player_cards').select('*').eq('owner_id',userId).is('retired_at',null).order('obtained_at',{ascending:false}),supabase.from('upgrades').select('*').eq('is_active',true).order('base_price'),supabase.from('player_upgrades').select('*').eq('owner_id',userId),supabase.from('pack_types').select('*').eq('is_active',true).order('cost'),supabase.rpc('get_pack_status'),supabase.from('player_badges').select('badges(*)').eq('owner_id',userId),supabase.from('patch_notes').select('*').eq('is_published',true).order('published_at',{ascending:false})];const results=await Promise.all(queries);const failed=results.find(result=>result.error);if(failed)throw failed.error;const [sync,cards,sets,inventory,upgrades,playerUpgrades,packs,packStatus,badges,notes]=results;state.profile=sync.data.profile;state.clickPower=Number(sync.data.click_power);state.eps=Number(sync.data.eps);state.cards=cards.data||[];state.sets=sets.data||[];state.inventory=inventory.data||[];state.upgrades=upgrades.data||[];state.playerUpgrades=playerUpgrades.data||[];state.packs=packs.data||[];state.packStatus=packStatus.data||null;state.badges=(badges.data||[]).map(row=>row.badges).filter(Boolean);state.notes=notes.data||[];renderAll();subscribe();if(Number(sync.data.offline_gain)>0)notify(`Çevrimdışı üretim: +${fmt(sync.data.offline_gain)} enerji`)}
async function refreshProfile(){if(!state.session)return;const {data,error}=await supabase.rpc('sync_energy');if(error)throw error;state.profile=data.profile;state.clickPower=Number(data.click_power);state.eps=Number(data.eps);renderHeader();renderHome()}
async function refreshInventory(){const {data,error}=await supabase.from('player_cards').select('*').eq('owner_id',state.session.user.id).is('retired_at',null).order('obtained_at',{ascending:false});if(error)throw error;state.inventory=data||[];renderAll()}
async function refreshPackStatus(){const {data,error}=await supabase.rpc('get_pack_status');if(error)throw error;state.packStatus=data;renderHome()}
function subscribe(){state.channels.forEach(channel=>supabase.removeChannel(channel));state.channels=[supabase.channel(`catalog-${state.session.user.id}`).on('postgres_changes',{event:'*',schema:'public',table:'cards'},()=>loadGame().catch(report)).subscribe(),supabase.channel(`inventory-${state.session.user.id}`).on('postgres_changes',{event:'*',schema:'public',table:'player_cards',filter:`owner_id=eq.${state.session.user.id}`},()=>refreshInventory().catch(report)).subscribe()]}

function cardMarkup(card,{locked=false,count=0,isNew=false,compact=false}={}){const art=locked?'?':card.image_url?`<img src="${safe(card.image_url)}" alt="${safe(card.name)}" loading="lazy">`:safe(card.symbol||'✦');return `<article class="cv-card rarity-${safe(card.rarity)} ${locked?'locked':''} ${compact?'compact-card':''}" data-card="${card.id}">${isNew&&!locked?'<span class="new-card-badge">YENİ</span>':''}<div class="card-art">${art}</div><div class="card-info"><small>${safe(card.code)} · ${safe(rarityNames[card.rarity]||card.rarity)}</small><h3>${locked?'Keşfedilmemiş kart':safe(card.name)}</h3><div class="card-meta"><span>◆ ${fmt(card.score)}</span><span>${count?`×${count}`:safe(cardSet(card))}</span></div></div></article>`}
function renderHeader(){if(!state.profile)return;$('headerAvatar').textContent=initials(state.profile.username);$('headerGold').textContent=fmt(state.profile.gold);$('headerEnergy').textContent=fmt(state.profile.energy)}
function renderHome(){if(!state.profile)return;const level=levelInfo();const cap=capacity();const energy=Number(state.profile.energy);$('energyValue').textContent=fmt(Math.min(energy,cap));$('capacityValue').textContent=`/ ${fmt(cap)} kapasite`;$('epsValue').textContent=fmt(state.eps);$('clickPowerValue').textContent=fmt(state.clickPower);$('collectionScoreValue').textContent=fmt(collectionScore());$('clickGain').textContent=`+${fmt(state.clickPower)}`;$('levelLabel').textContent=`Seviye ${level.level}`;$('levelProgress').textContent=`${fmt(level.current)} / ${fmt(level.needed)}`;$('levelBar').style.width=`${level.percent}%`;$('coreButton').disabled=energy>=cap||state.busy;const dailyRemaining=state.packStatus?.next_daily_at?new Date(state.packStatus.next_daily_at)-Date.now():0;const countdown=dailyRemaining>0?`${Math.floor(dailyRemaining/3600000)}sa ${Math.floor(dailyRemaining%3600000/60000)}dk`:'';$('packList').innerHTML=state.packs.map(pack=>{const stock=state.packStatus?.pack_availability?.[pack.key]??state.packStatus?.available_card_count;const outOfStock=Number(stock)===0;const cooling=pack.daily&&dailyRemaining>0;const affordable=pack.daily||energy>=Number(pack.cost);const available=!outOfStock&&!cooling&&affordable;return `<article class="panel pack-card purchase-card ${available?'affordable':'unavailable'}"><span class="pack-icon">${pack.daily?'◉':'✦'}</span><h3>${safe(pack.name)}</h3><p>${safe(pack.description||'Yeni bir kart keşfet.')}</p><button class="button ${available?'primary':'ghost'}" data-pack="${safe(pack.key)}" ${available?'':'disabled'}>${outOfStock?'Stok yok':cooling?`Yenilenme: ${countdown}`:!affordable?`Yetersiz enerji · ${fmt(pack.cost)} ⚡`:pack.daily?'Günlük paketi aç':`${fmt(pack.cost)} enerji · Aç`}</button></article>`}).join('')||empty('Aktif paket bulunmuyor.');const recent=state.inventory.slice(0,5).map(item=>state.cards.find(card=>card.id===item.card_id)).filter(Boolean);$('recentCards').innerHTML=recent.map(card=>cardMarkup(card)).join('')||empty('Henüz kart kazanmadın.');$('upgradeList').innerHTML=state.upgrades.map(upgrade=>{const current=state.playerUpgrades.find(row=>row.upgrade_key===upgrade.key)?.level||0;const cost=Math.floor(Number(upgrade.base_price)*Number(upgrade.price_growth)**current);const maxed=upgrade.max_level!==null&&current>=upgrade.max_level;const affordable=energy>=cost;const available=!maxed&&affordable;return `<article class="upgrade purchase-card ${available?'affordable':'unavailable'}"><span>${safe(upgrade.icon||'⚙')}</span><div><strong>${safe(upgrade.name)} · Lv.${current}</strong><small>${safe(upgrade.description||'')}</small></div><button class="button ${available?'primary':'ghost'}" data-upgrade="${safe(upgrade.key)}" ${available?'':'disabled'}>${maxed?'MAX':affordable?`${fmt(cost)} ⚡ · Yükselt`:`Yetersiz · ${fmt(cost)} ⚡`}</button></article>`}).join('')||empty('Geliştirme bulunmuyor.')}
function renderCollection(){const query=$('cardSearch').value.trim().toLocaleLowerCase('tr');const rarity=$('rarityFilter').value;const set=$('setFilter').value;const onlyOwned=$('ownedOnly').checked;const unique=state.cards.filter(card=>owned(card.id)).length;const percent=state.cards.length?Math.round(unique/state.cards.length*100):0;$('collectionSummary').textContent=`${unique} / ${state.cards.length} farklı kart keşfedildi`;$('collectionPercent').textContent=`${percent}%`;const current=$('setFilter').value;$('setFilter').innerHTML='<option value="all">Tüm setler</option>'+state.sets.map(item=>`<option value="${item.id}">${safe(item.name)}</option>`).join('');$('setFilter').value=[...$('setFilter').options].some(option=>option.value===current)?current:'all';const cards=state.cards.filter(card=>(!query||[card.name,card.code,card.subtitle,card.illustrator].some(value=>String(value||'').toLocaleLowerCase('tr').includes(query)))&&(rarity==='all'||card.rarity===rarity)&&(set==='all'||card.set_id===set)&&(!onlyOwned||owned(card.id)));$('collectionGrid').innerHTML=cards.map(card=>cardMarkup(card,{locked:!owned(card.id),count:owned(card.id)})).join('')||empty('Bu filtrelerle eşleşen kart yok.');renderFusion()}
function renderFusion(){const current=$('fusionRecipe').value;const recipes=[];for(const card of state.cards){const standard=state.inventory.filter(copy=>copy.card_id===card.id&&copy.variant==='Standard').length;const foil=state.inventory.filter(copy=>copy.card_id===card.id&&copy.variant==='Foil').length;if(standard>=5)recipes.push({value:`${card.id}|Standard`,label:`${card.name}: Standard ${standard}/5 → Foil`});if(foil>=3)recipes.push({value:`${card.id}|Foil`,label:`${card.name}: Foil ${foil}/3 → Gold Foil`})}$('fusionRecipe').innerHTML=recipes.map(item=>`<option value="${safe(item.value)}">${safe(item.label)}</option>`).join('')||'<option value="">Birleştirilebilir kart yok</option>';$('fusionRecipe').value=recipes.some(item=>item.value===current)?current:recipes[0]?.value||'';$('fusionButton').disabled=!recipes.length}
async function fuseCards(event){event.preventDefault();const [card,variant]=$('fusionRecipe').value.split('|');if(!card||!variant)return;if(!confirm(`${variant} kopyaları kalıcı olarak birleştirilsin mi?`))return;const {data,error}=await supabase.rpc('fuse_card_copies',{p_card:card,p_from_variant:variant});if(error)throw error;await loadGame();notify(`${data.to_variant} varyantı oluşturuldu.`)}
function profileMarkup(profile,inventory,badges=[],rank=null){const level=levelInfo(profile.total_energy);const unique=new Set(inventory.map(item=>item.card_id)).size;const variants=inventory.filter(item=>item.variant&&item.variant!=='Standard').length;const score=collectionScore(inventory);const latestCopy=[...inventory].sort((a,b)=>new Date(b.obtained_at)-new Date(a.obtained_at))[0];const latestCard=latestCopy&&state.cards.find(card=>card.id===latestCopy.card_id);const best=[...inventory].sort((a,b)=>Number(state.cards.find(card=>card.id===b.card_id)?.score||0)-Number(state.cards.find(card=>card.id===a.card_id)?.score||0)).slice(0,5).map(item=>state.cards.find(card=>card.id===item.card_id)).filter(Boolean);return `<section class="panel profile-banner"><div class="profile-avatar">${profile.avatar_url?`<img src="${safe(profile.avatar_url)}" alt="${safe(profile.username)}">`:safe(initials(profile.username))}</div><div><p class="kicker">OYUNCU PROFİLİ</p><h2>${safe(profile.username)}</h2><p class="muted">${new Date(profile.created_at).toLocaleDateString('tr-TR')} tarihinden beri CollectVerse'de</p></div>${rank?`<div class="profile-rank"><span>GLOBAL SIRA</span><strong>#${rank}</strong></div>`:''}</section><div class="profile-stats"><article class="panel"><span>Seviye</span><strong>${level.level}</strong></article><article class="panel"><span>Koleksiyon puanı</span><strong>${fmt(score)}</strong></article><article class="panel"><span>Farklı kart</span><strong>${unique} / ${state.cards.length}</strong></article><article class="panel"><span>Toplam varyant</span><strong>${variants}</strong></article><article class="panel"><span>Toplam tıklama</span><strong>${fmt(profile.total_clicks)}</strong></article></div>${latestCard?`<section class="panel profile-latest"><div>${cardMarkup(latestCard,{compact:true,isNew:isNewCard(latestCard.id,inventory)})}</div><div><p class="kicker">SON KAZANILAN KART</p><h2>${safe(latestCard.name)}</h2><p class="muted">${safe(latestCopy.variant)} · ${new Date(latestCopy.obtained_at).toLocaleString('tr-TR')}</p></div></section>`:''}<div class="profile-sections"><section><div class="section-head"><div><p class="kicker">KART VİTRİNİ</p><h2>En değerli kartlar</h2></div></div><div class="card-row">${best.map(card=>cardMarkup(card,{count:inventory.filter(item=>item.card_id===card.id).length,isNew:isNewCard(card.id,inventory)})).join('')||empty('Vitrinde kart yok.')}</div></section><section><div class="section-head"><div><p class="kicker">BAŞARILAR</p><h2>Rozetler</h2></div></div><div class="badge-grid">${badges.map(badge=>`<article class="panel badge"><span>${safe(badge.icon||'✦')}</span><div><strong>${safe(badge.name)}</strong><small>${safe(badge.description)}</small></div></article>`).join('')||empty('Henüz rozet yok.')}</div></section></div>`}
function renderProfile(){if(!state.profile)return;const rank=state.scoreboard.find(row=>row.user_id===state.profile.id)?.rank;$('profileContent').innerHTML=profileMarkup(state.profile,state.inventory,state.badges,rank)}
async function openPlayer(userId){if(userId===state.session.user.id){routeTo('profile');return}routeTo('player');$('publicProfileContent').innerHTML=empty('Oyuncu profili yükleniyor…');const [profile,inventory,badges]=await Promise.all([supabase.from('profiles').select('id,username,avatar_url,total_energy,total_clicks,created_at').eq('id',userId).single(),supabase.from('player_cards').select('*').eq('owner_id',userId).is('retired_at',null).order('obtained_at',{ascending:false}),supabase.from('player_badges').select('badges(*)').eq('owner_id',userId)]);const failed=[profile,inventory,badges].find(result=>result.error);if(failed)throw failed.error;state.selectedPlayer={profile:profile.data,inventory:inventory.data||[]};const rank=state.scoreboard.find(row=>row.user_id===userId)?.rank;$('publicProfileContent').innerHTML=profileMarkup(profile.data,inventory.data||[],(badges.data||[]).map(row=>row.badges).filter(Boolean),rank)}
function renderNews(){$('newsList').innerHTML=state.notes.map(note=>`<article class="panel news-item"><p class="kicker">SÜRÜM ${safe(note.version)}</p><h3>${safe(note.title)}</h3><p class="muted">${safe(note.body)}</p>${Array.isArray(note.changes)?`<ul>${note.changes.map(item=>`<li>${safe(item)}</li>`).join('')}</ul>`:''}</article>`).join('')||empty('Henüz yayımlanmış bir yama notu yok.')}
function renderAll(){renderHeader();renderHome();renderCollection();renderProfile();renderNews()}
function empty(text){return `<p class="empty">${safe(text)}</p>`}

function clickCore(event){if(!state.profile||state.busy)return;const cap=capacity();const energy=Number(state.profile.energy);const gain=Math.min(state.clickPower,Math.max(0,cap-energy));if(gain<=0){notify('Enerji kapasitesi doldu. Daha fazla enerji için önce enerji harca.','error');return}const button=$('coreButton');const gainText=document.createElement('span');gainText.className='core-float-gain';gainText.textContent=`+${fmt(gain)}`;gainText.style.setProperty('--float-x',`${Math.round(Math.random()*44-22)}px`);if(event?.clientX!==undefined){const rect=button.getBoundingClientRect();gainText.style.left=`${Math.max(18,Math.min(event.clientX-rect.left,rect.width-18))}px`;gainText.style.top=`${Math.max(24,Math.min(event.clientY-rect.top,rect.height-38))}px`}button.append(gainText);gainText.addEventListener('animationend',()=>gainText.remove(),{once:true});state.pendingClicks+=1;state.profile.energy=energy+gain;state.profile.total_energy=Number(state.profile.total_energy)+gain;state.profile.total_clicks=Number(state.profile.total_clicks)+1;renderHeader();renderHome()}
const renderHomeBase=renderHome;
function decorateNewCards(){for(const rootId of ['recentCards','collectionGrid','profileContent']){const root=$(rootId);if(!root)continue;qa('[data-card]',root).forEach(card=>{if(!isNewCard(card.dataset.card)||card.classList.contains('locked')||card.querySelector('.new-card-badge'))return;const badge=document.createElement('span');badge.className='new-card-badge';badge.textContent='YENİ';card.append(badge)})}}
renderHome=function(){renderHomeBase();decorateNewCards();if(!state.profile)return;const full=Number(state.profile.energy)>=capacity();const button=$('coreButton');button.disabled=state.busy;button.classList.toggle('capacity-full',full);button.setAttribute('aria-disabled',String(full));const label=q('small',button);if(label)label.textContent=full?'KAPASİTE DOLDU':'ÜRETMEK İÇİN TIKLA'};
const renderCollectionBase=renderCollection;
renderCollection=function(){renderCollectionBase();decorateNewCards()};
async function flushClicks(strict=false){if(!state.pendingClicks||!state.session)return true;const clicks=state.pendingClicks;state.pendingClicks=0;const {data,error}=await supabase.rpc('produce_energy',{p_clicks:clicks});if(error){state.pendingClicks+=clicks;report(error);if(strict)throw error;return false}state.profile=data.profile;state.clickPower=Number(data.click_power);state.eps=Number(data.eps);renderAll();return true}
async function buyUpgrade(key){if(state.busy)return;state.busy=true;try{await flushClicks(true);const {error}=await supabase.rpc('buy_upgrade',{p_key:key});if(error)throw error;await loadGame();notify('Geliştirme satın alındı.')}catch(error){report(error)}finally{state.busy=false}}
async function openPack(key,button){if(state.busy)return;const stopLoading=setLoading(button,'Paket açılıyor…');state.busy=true;try{await flushClicks(true);const {data,error}=await supabase.rpc('open_pack',{p_key:key});if(error)throw error;state.profile=data.profile;await Promise.all([refreshInventory(),refreshPackStatus()]);const card=state.cards.find(item=>item.id===data.card.id)||data.card;const dialog=$('packDialog');dialog.className=`dialog pack-dialog pack-rarity-${safe(card.rarity)}`;$('packResult').innerHTML=cardMarkup(card,{isNew:true,compact:true});dialog.showModal();notify(`${rarityNames[card.rarity]||card.rarity} kart keşfedildi.`)}catch(error){report(error)}finally{state.busy=false;stopLoading();renderHome()}}
async function loadCardMarketEstimate(card,variant){const target=$('cardMarketEstimate');if(!target)return;const {data,error}=await supabase.rpc('get_card_price_stats',{p_card:card.id,p_variant:variant});if(error){target.innerHTML='<span>Pazar tahmini</span><strong>Şu anda hesaplanamıyor</strong>';return}const value=Number(data?.suggested_price);target.innerHTML=`<span>Tahmini pazar değeri · ${safe(variant)}</span><strong>${value>0?`${fmt(value)} Gold`:'Veri yok'}</strong><small>${Number(data?.sales_count)||0} tamamlanmış satış temel alındı</small>`}
function showCard(id){const card=state.cards.find(item=>item.id===id);if(!card)return;const source=state.selectedPlayer&&location.hash==='#player'?state.selectedPlayer.inventory:state.inventory;const copies=source.filter(item=>item.card_id===id);const count=copies.length;const variant=copies[0]?.variant||'Standard';const copyDetails=copies.map(copy=>`<li><code>${safe(copy.id.slice(0,8))}</code> · ${safe(copy.variant)} · ${safe(copy.condition)}${copy.serial_number?` · #${copy.serial_number}/${card.max_supply||'?'}`:''}</li>`).join('');$('cardDialogBody').innerHTML=`<div class="dialog-card"><div>${cardMarkup(card,{locked:!count,count,isNew:isNewCard(id,source)})}</div><div><p class="kicker">${safe(rarityNames[card.rarity]||card.rarity)} · ${safe(card.code)}</p><h2>${count?safe(card.name):'Keşfedilmemiş kart'}</h2><p class="muted">${count?safe(card.description||card.subtitle||'Bu kartın hikâyesi henüz yazılmadı.'):'Bu kartı paketlerden keşfedebilirsin.'}</p><p><strong>◆ ${fmt(card.score)}</strong> koleksiyon puanı · <strong>⚡ ${fmt(card.power)}</strong> güç</p><div id="cardMarketEstimate" class="market-estimate"><span>Tahmini pazar değeri</span><strong>Hesaplanıyor…</strong></div><div class="card-facts"><span>${safe(card.series_name||'CollectVerse')}</span><span>${safe(card.season_name||'Ana sezon')}</span><span>${safe(card.edition_name||'Standard Edition')}</span>${card.illustrator?`<span>Çizer: ${safe(card.illustrator)}</span>`:''}${card.is_signed?'<span>İmzalı</span>':''}${card.is_limited?'<span>Limited</span>':''}</div>${count?`<h3>Kart kopyaları</h3><ul class="copy-list">${copyDetails}</ul>`:'<p class="muted">Koleksiyonunda bulunmuyor.</p>'}</div></div>`;$('cardDialog').className=`dialog card-detail-dialog rarity-${safe(card.rarity)}`;$('cardDialog').showModal();loadCardMarketEstimate(card,variant).catch(report)}

async function loadScoreboard(){const {data,error}=await supabase.rpc('get_scoreboard',{p_limit:100});if(error)throw error;state.scoreboard=data||[];const me=state.scoreboard.find(row=>row.user_id===state.session.user.id);$('myRank').innerHTML=me?`<strong>#${me.rank}</strong> · ${safe(me.username)} — ${fmt(me.collection_score)} puan`:'Henüz sıralamaya girmedin.';$('scoreboardList').innerHTML=state.scoreboard.map(row=>`<div class="leader-row"><strong>#${row.rank}</strong><button class="player-link" data-player="${row.user_id}">${safe(row.username)} · Seviye ${row.level}</button><span>${row.unique_cards} kart</span><strong>${fmt(row.collection_score)}</strong></div>`).join('')||empty('Sıralamada oyuncu yok.')}
async function loadMarket(){const maintenance=await Promise.all([supabase.rpc('settle_expired_auctions'),supabase.rpc('ensure_friday_market')]);const maintenanceFailure=maintenance.find(result=>result.error);if(maintenanceFailure)throw maintenanceFailure.error;const uid=state.session.user.id;const [listings,copies,reservations]=await Promise.all([supabase.from('market_listings').select('*,cards(*),profiles!market_listings_seller_id_fkey(username)').eq('status','active').order('created_at',{ascending:false}),supabase.from('player_cards').select('*,cards(*)').eq('owner_id',uid).is('retired_at',null),supabase.from('trade_reserved_cards').select('player_card_id').eq('owner_id',uid)]);const failed=[listings,copies,reservations].find(result=>result.error);if(failed)throw failed.error;state.listings=listings.data||[];state.tradeReserved=(reservations.data||[]).map(item=>item.player_card_id);const listed=new Set(state.listings.map(item=>item.player_card_id));const reserved=new Set(state.tradeReserved);const available=(copies.data||[]).filter(item=>!listed.has(item.id)&&!reserved.has(item.id));for(const id of ['fixedCopy','auctionCopy','buybackCopy'])$(id).innerHTML=available.length?available.map(item=>`<option value="${item.id}">${safe(item.cards.name)} · ${safe(item.variant)} · ${safe(item.condition)}${item.serial_number?` · #${item.serial_number}`:''}</option>`).join(''):'<option value="">Satılabilir kart yok</option>';const mine=state.listings.filter(item=>item.seller_id===uid);const others=state.listings.filter(item=>item.seller_id!==uid);$('marketListings').innerHTML=others.map(listingMarkup).join('')||empty('Aktif ilan yok.');$('myListings').innerHTML=mine.map(listingMarkup).join('')||empty('Aktif ilanın yok.')}
function listingMarkup(item){const card=item.cards||{};const mine=item.seller_id===state.session.user.id;const price=Number(item.current_bid||item.price||item.base_price);const action=mine?`<button class="button ghost" data-cancel-listing="${item.id}">İptal et</button>`:item.listing_type==='auction'?`<input type="number" min="${price+1}" value="${price+1}" data-bid-value="${item.id}"><button class="button primary" data-bid-listing="${item.id}">Teklif ver</button>`:`<button class="button primary" data-buy-listing="${item.id}">Satın al</button>`;return `<article class="panel listing"><div class="card-art">${card.image_url?`<img src="${safe(card.image_url)}" alt="${safe(card.name)}">`:safe(card.symbol||'✦')}</div><div><p class="kicker">${item.source_type==='system'?'CUMA ÖZEL':item.listing_type==='auction'?'AÇIK ARTIRMA':'SABİT FİYAT'}</p><h3>${safe(card.name||'Kart')}</h3><span class="price">${fmt(price)} Gold</span><p class="muted">${item.source_type==='system'?'CollectVerse Sistemi':safe(item.profiles?.username||'Oyuncu')}</p></div><div class="listing-actions">${action}</div></article>`}
async function marketRpc(name,args,message,button){const stopLoading=setLoading(button,'İşleniyor…');try{const {data,error}=await supabase.rpc(name,args);if(error)throw error;if(data?.profile)state.profile=data.profile;notify(message);await Promise.all([refreshInventory(),loadMarket()])}finally{stopLoading()}}

function tradeCardLabel(copy){const card=copy.cards||state.cards.find(item=>item.id===copy.card_id)||{};return `${card.name||'Kart'} · ${copy.variant||'Standard'}${copy.serial_number?` · #${copy.serial_number}`:''}`}
function fillTradeOfferedCards(){const reserved=new Set(state.tradeReserved);const listed=new Set(state.listings.map(item=>item.player_card_id));const copies=state.inventory.filter(copy=>!reserved.has(copy.id)&&!listed.has(copy.id));$('tradeOfferedCards').innerHTML=copies.map(copy=>`<option value="${copy.id}">${safe(tradeCardLabel(copy))}</option>`).join('')||'<option disabled>Uygun kart kopyası yok</option>'}
async function findTradePlayer(){const username=$('tradeUsername').value.trim();if(!username)return;const {data:profile,error}=await supabase.from('profiles').select('id,username').ilike('username',username).maybeSingle();if(error)throw error;if(!profile||profile.id===state.session.user.id){$('tradeRecipientId').value='';$('tradeTargetStatus').textContent=profile?'Kendinle takas yapamazsın.':'Oyuncu bulunamadı.';$('tradeRequestedCards').disabled=true;$('tradeRequestedCards').innerHTML='';return}const [copies,listings,reservations]=await Promise.all([supabase.from('player_cards').select('*,cards(*)').eq('owner_id',profile.id).is('retired_at',null).order('obtained_at',{ascending:false}),supabase.from('market_listings').select('player_card_id').eq('seller_id',profile.id).eq('status','active'),supabase.from('trade_reserved_cards').select('player_card_id').eq('owner_id',profile.id)]);const failed=[copies,listings,reservations].find(result=>result.error);if(failed)throw failed.error;const listed=new Set((listings.data||[]).map(item=>item.player_card_id));const reserved=new Set((reservations.data||[]).map(item=>item.player_card_id));const available=(copies.data||[]).filter(copy=>!listed.has(copy.id)&&!reserved.has(copy.id));$('tradeRecipientId').value=profile.id;$('tradeTargetStatus').textContent=`${profile.username} bulundu · ${available.length} uygun kart`;$('tradeRequestedCards').disabled=false;$('tradeRequestedCards').innerHTML=available.map(copy=>`<option value="${copy.id}">${safe(tradeCardLabel(copy))}</option>`).join('')||'<option disabled>Uygun kart kopyası yok</option>'}
function tradeMarkup(trade,incoming){const items=trade.trade_offer_items||[];const offered=items.filter(item=>item.side==='offered').map(item=>tradeCardLabel(item.player_cards||{}));const requested=items.filter(item=>item.side==='requested').map(item=>tradeCardLabel(item.player_cards||{}));const pending=trade.status==='pending'&&new Date(trade.expires_at)>new Date();const actions=pending?(incoming?`<button class="button primary" data-trade-accept="${trade.id}">Kabul et</button><button class="button ghost" data-trade-decline="${trade.id}">Reddet</button>`:`<button class="button ghost" data-trade-cancel="${trade.id}">İptal et</button>`):'';return `<article class="panel trade-offer"><div class="trade-offer-head"><div><p class="kicker">${incoming?'GELEN TEKLİF':'GÖNDERİLEN TEKLİF'}</p><h3>${safe(incoming?trade.proposer?.username:trade.recipient?.username)}</h3></div><span class="trade-status status-${safe(trade.status)}">${safe(trade.status)}</span></div><div class="trade-summary"><div><strong>Verilen</strong><p>${offered.map(safe).join('<br>')||'Kart yok'}</p>${trade.offered_gold?`<b>${fmt(trade.offered_gold)} Gold</b>`:''}</div><span>⇄</span><div><strong>İstenen</strong><p>${requested.map(safe).join('<br>')||'Kart yok'}</p>${trade.requested_gold?`<b>${fmt(trade.requested_gold)} Gold</b>`:''}</div></div><small class="muted">Son: ${new Date(trade.expires_at).toLocaleString('tr-TR')}</small><div class="trade-actions">${actions}</div></article>`}
async function loadTrades(){const maintenance=await supabase.rpc('expire_trade_offers');if(maintenance.error)throw maintenance.error;const uid=state.session.user.id;const [trades,reserved,listings]=await Promise.all([supabase.from('trade_offers').select('*,proposer:profiles!trade_offers_proposer_id_fkey(username),recipient:profiles!trade_offers_recipient_id_fkey(username),trade_offer_items(*,player_cards(*,cards(name,code,rarity)))').or(`proposer_id.eq.${uid},recipient_id.eq.${uid}`).order('created_at',{ascending:false}).limit(50),supabase.from('trade_reserved_cards').select('player_card_id').eq('owner_id',uid),supabase.from('market_listings').select('player_card_id').eq('seller_id',uid).eq('status','active')]);const failed=[trades,reserved,listings].find(result=>result.error);if(failed)throw failed.error;state.trades=trades.data||[];state.tradeReserved=(reserved.data||[]).map(item=>item.player_card_id);state.listings=listings.data||[];fillTradeOfferedCards();$('incomingTrades').innerHTML=state.trades.filter(item=>item.recipient_id===uid).map(item=>tradeMarkup(item,true)).join('')||empty('Gelen takas teklifi yok.');$('outgoingTrades').innerHTML=state.trades.filter(item=>item.proposer_id===uid).map(item=>tradeMarkup(item,false)).join('')||empty('Gönderilmiş takas teklifin yok.')}
async function createTrade(event){event.preventDefault();const recipient=$('tradeRecipientId').value;if(!recipient)return notify('Önce geçerli bir oyuncu bul.','error');const offered=[...$('tradeOfferedCards').selectedOptions].map(option=>option.value);const requested=[...$('tradeRequestedCards').selectedOptions].map(option=>option.value);const offeredGold=Number($('tradeOfferedGold').value)||0;const requestedGold=Number($('tradeRequestedGold').value)||0;if(offeredGold<0||requestedGold<0)return notify('Gold miktarı negatif olamaz.','error');if(!offered.length&&!requested.length&&!offeredGold&&!requestedGold)return notify('En az bir kart veya Gold eklemelisin.','error');const stopLoading=setLoading(q('[type="submit"]',event.currentTarget),'Teklif gönderiliyor…');try{const {error}=await supabase.rpc('create_trade_offer',{p_recipient:recipient,p_offered_cards:offered,p_requested_cards:requested,p_offered_gold:offeredGold,p_requested_gold:requestedGold,p_expires_hours:Number($('tradeExpiry').value)});if(error)throw error;notify('Takas teklifi gönderildi.');$('tradeForm').reset();$('tradeRecipientId').value='';$('tradeTargetStatus').textContent='Önce takas yapmak istediğin oyuncuyu bul.';$('tradeRequestedCards').disabled=true;$('tradeRequestedCards').innerHTML='';await loadTrades()}finally{stopLoading()}}
async function tradeAction(name,id,action,message,button){const stopLoading=setLoading(button,'İşleniyor…');try{const args=name==='close_trade_offer'?{p_trade:id,p_action:action}:{p_trade:id};const {error}=await supabase.rpc(name,args);if(error)throw error;notify(message);await loadGame();await loadTrades()}finally{stopLoading()}}

function priceChart(history){if(!history?.length)return '<p class="muted">Bu varyant için henüz tamamlanmış satış yok.</p>';const values=history.map(item=>Number(item.average));const max=Math.max(...values,1);const min=Math.min(...values);const span=Math.max(1,max-min);const points=values.map((value,index)=>`${history.length===1?50:index/(history.length-1)*100},${44-(value-min)/span*38}`).join(' ');return `<svg class="price-chart" viewBox="0 0 100 48" preserveAspectRatio="none" role="img" aria-label="Son 30 günlük fiyat geçmişi"><polyline points="${points}"/></svg>`}
async function renderPriceGuide(){const select=$('fixedCopy');let guide=$('priceGuide');if(!guide){guide=document.createElement('div');guide.id='priceGuide';guide.className='price-guide';select.after(guide)}const copy=state.inventory.find(item=>item.id===select.value);if(!copy){guide.innerHTML='<p class="muted">Fiyat bilgisi için bir kart seç.</p>';return}guide.innerHTML='<p class="muted">Fiyat geçmişi yükleniyor…</p>';const {data,error}=await supabase.rpc('get_card_price_stats',{p_card:copy.card_id,p_variant:copy.variant});if(error)throw error;if(select.value!==copy.id)return;$('fixedPrice').value=data.suggested_price;guide.innerHTML=`<div class="price-stats"><span>Taban<strong>${fmt(data.base_price)}</strong></span><span>Ortalama<strong>${data.average_price===null?'—':fmt(data.average_price)}</strong></span><span>Son satış<strong>${data.last_price===null?'—':fmt(data.last_price)}</strong></span></div>${priceChart(data.history)}<small>${fmt(data.sales_count)} satış · Önerilen fiyat: ${fmt(data.suggested_price)} Gold</small>`}
function setupPriceGuide(){const select=$('fixedCopy');select.addEventListener('change',()=>renderPriceGuide().catch(report));new MutationObserver(()=>renderPriceGuide().catch(report)).observe(select,{childList:true})}
setupPriceGuide();
function applyMarketFilters(){if(!state.session)return;const query=$('marketSearch').value.trim().toLocaleLowerCase('tr');const rarity=$('marketRarity').value;const min=Number($('marketMinPrice').value)||0;const max=Number($('marketMaxPrice').value)||Infinity;const filtered=state.listings.filter(item=>item.seller_id!==state.session.user.id).filter(item=>{const price=Number(item.current_bid||item.price||0);return(!query||[item.cards?.name,item.cards?.code,item.profiles?.username].some(value=>String(value||'').toLocaleLowerCase('tr').includes(query)))&&(rarity==='all'||item.cards?.rarity===rarity)&&price>=min&&price<=max});$('marketListings').innerHTML=filtered.map(listingMarkup).join('')||empty('Bu filtrelerle eşleşen aktif ilan yok.')}
function setupMarketFilters(){const toolbar=document.createElement('div');toolbar.className='toolbar market-filter-bar';toolbar.innerHTML='<input id="marketSearch" type="search" placeholder="Kart, kod veya satıcı ara…"><select id="marketRarity"><option value="all">Tüm nadirlikler</option><option value="common">Common</option><option value="uncommon">Uncommon</option><option value="rare">Rare</option><option value="epic">Epic</option><option value="legendary">Legendary</option><option value="mythic">Mythic</option><option value="secret">Secret</option></select><input id="marketMinPrice" type="number" min="0" placeholder="Min. Gold"><input id="marketMaxPrice" type="number" min="0" placeholder="Maks. Gold"><button id="clearMarketFilters" class="button ghost" type="button">Temizle</button>';$('marketListings').before(toolbar);for(const id of ['marketSearch','marketRarity','marketMinPrice','marketMaxPrice'])$(id).addEventListener('input',applyMarketFilters);$('clearMarketFilters').addEventListener('click',()=>{for(const id of ['marketSearch','marketMinPrice','marketMaxPrice'])$(id).value='';$('marketRarity').value='all';applyMarketFilters()})}
setupMarketFilters();
const loadMarketBase=loadMarket;
loadMarket=async function(){await loadMarketBase();await loadWatchlist();applyMarketFilters();enhanceListingWatchButtons()};
async function loadWatchlist(){if(!state.session)return;const {data,error}=await supabase.from('card_watchlist').select('*,cards(*)').eq('owner_id',state.session.user.id).order('created_at',{ascending:false});if(error)throw error;state.watchlist=data||[];renderWatchlist()}
function renderWatchlist(){const root=$('watchlistGrid');if(!root)return;root.innerHTML=state.watchlist.map(item=>{const priceOf=listing=>Number(listing.current_bid||listing.price||0);const active=state.listings.filter(listing=>listing.card_id===item.card_id&&String(listing.card_variant||'Standard')===item.variant&&listing.status==='active').sort((a,b)=>priceOf(a)-priceOf(b))[0];return `<article class="panel watch-card"><div>${cardMarkup(item.cards)}<p><strong>${safe(item.variant)}</strong></p></div><div><label>Hedef fiyat<input type="number" min="1" value="${item.target_price||''}" data-watch-target="${item.card_id}|${safe(item.variant)}" placeholder="Gold"></label><p class="muted">${active?`En düşük aktif ilan: <strong>${fmt(priceOf(active))} Gold</strong>`:'Aktif ilan yok'}</p><div class="trade-actions"><button class="button primary" data-save-watch="${item.card_id}|${safe(item.variant)}">Güncelle</button><button class="button ghost" data-remove-watch="${item.card_id}|${safe(item.variant)}">Kaldır</button></div></div></article>`}).join('')||empty('Henüz izlediğin kart yok. Pazardaki yıldız düğmesiyle kart ekleyebilirsin.')}
function enhanceListingWatchButtons(){qa('#marketListings .listing').forEach(article=>{const action=article.querySelector('[data-buy-listing],[data-bid-listing]');if(!action)return;const listing=state.listings.find(item=>item.id===(action.dataset.buyListing||action.dataset.bidListing));if(!listing||article.querySelector('[data-watch-listing]'))return;const button=document.createElement('button');button.type='button';button.className='button ghost';button.dataset.watchListing=listing.id;button.textContent='☆ İzle';article.querySelector('.listing-actions')?.append(button)})}
async function saveWatch(card,variant,target){const {error}=await supabase.rpc('set_card_watch',{p_card:card,p_variant:variant,p_target_price:target||null});if(error)throw error;await loadWatchlist();notify('Kart izleme listesine eklendi.')}
async function removeWatch(card,variant){const {error}=await supabase.rpc('remove_card_watch',{p_card:card,p_variant:variant});if(error)throw error;await loadWatchlist();notify('Kart izleme listesinden kaldırıldı.')}
async function loadNotifications(){if(!state.session)return;const refresh=await supabase.rpc('refresh_daily_notification');if(refresh.error)throw refresh.error;const {data,error}=await supabase.from('notifications').select('*').eq('owner_id',state.session.user.id).order('created_at',{ascending:false}).limit(50);if(error)throw error;state.notifications=data||[];const unread=state.notifications.filter(item=>!item.read_at).length;$('notificationCount').textContent=unread;$('notificationCount').classList.toggle('hidden',!unread);$('notificationList').innerHTML=state.notifications.map(item=>`<article class="notification-item ${item.read_at?'':'unread'}"><div><strong>${safe(item.title)}</strong><p>${safe(item.body)}</p><small>${new Date(item.created_at).toLocaleString('tr-TR')}</small></div>${item.read_at?'':`<button class="button ghost" data-read-notification="${item.id}">Okundu</button>`}</article>`).join('')||empty('Yeni bildirimin yok.')}
function setupWatchAndNotifications(){const navButton=document.createElement('button');navButton.dataset.route='watchlist';navButton.innerHTML='<span>☆</span>İzleme listesi';q('[data-route="trades"]',$('mainNav')).before(navButton);const page=document.createElement('section');page.id='watchlistPage';page.className='page';page.innerHTML='<div class="page-hero"><div><p class="kicker">FİYAT TAKİBİ</p><h2>İzleme listesi</h2><p class="muted">Kartları ve hedef fiyatlarını takip et.</p></div><button id="refreshWatchlistBtn" class="button ghost">Yenile</button></div><div id="watchlistGrid" class="watchlist-grid"></div>';q('.content').append(page);const bell=document.createElement('button');bell.id='notificationButton';bell.className='notification-button';bell.type='button';bell.setAttribute('aria-label','Bildirimleri aç');bell.innerHTML='♢<span id="notificationCount" class="hidden">0</span>';q('.wallet').prepend(bell);const drawer=document.createElement('aside');drawer.id='notificationDrawer';drawer.className='notification-drawer hidden';drawer.innerHTML='<div class="panel-head"><div><p class="kicker">BİLDİRİMLER</p><h2>Bildirim merkezi</h2></div><button id="closeNotifications" class="icon-button" aria-label="Bildirimleri kapat">×</button></div><button id="readAllNotifications" class="button ghost full">Tümünü okundu işaretle</button><div id="notificationList" class="notification-list"></div>';document.body.append(drawer);$('refreshWatchlistBtn').addEventListener('click',()=>loadMarket().catch(report));bell.addEventListener('click',()=>{$('notificationDrawer').classList.toggle('hidden');loadNotifications().catch(report)});$('closeNotifications').addEventListener('click',()=>$('notificationDrawer').classList.add('hidden'));$('readAllNotifications').addEventListener('click',()=>supabase.rpc('mark_notifications_read',{p_notification:null}).then(({error})=>{if(error)throw error;return loadNotifications()}).catch(report));document.body.addEventListener('click',event=>{const watch=event.target.closest('[data-watch-listing]');const save=event.target.closest('[data-save-watch]');const remove=event.target.closest('[data-remove-watch]');const read=event.target.closest('[data-read-notification]');if(watch){const listing=state.listings.find(item=>item.id===watch.dataset.watchListing);if(!listing)return;const defaultPrice=Number(listing.current_bid||listing.price||0);const target=Number(prompt('Hedef fiyat kaç Gold olsun?',defaultPrice))||null;if(target&&target>0)saveWatch(listing.card_id,listing.card_variant||'Standard',target).catch(report)}if(save){const [card,variant]=save.dataset.saveWatch.split('|');const target=Number(q(`[data-watch-target="${card}|${variant}"]`)?.value)||null;if(target&&target>0)saveWatch(card,variant,target).catch(report);else notify('Hedef fiyat 1 Gold veya daha fazla olmalı.','error')}if(remove){const [card,variant]=remove.dataset.removeWatch.split('|');removeWatch(card,variant).catch(report)}if(read){supabase.rpc('mark_notifications_read',{p_notification:read.dataset.readNotification}).then(({error})=>{if(error)throw error;return loadNotifications()}).catch(report)}})}
setupWatchAndNotifications();
new MutationObserver(()=>enhanceListingWatchButtons()).observe($('marketListings'),{childList:true});
setInterval(()=>state.session&&loadNotifications().catch(report),20000);
const routeToBase=routeTo;
routeTo=function(route){routeToBase(route);if(route==='watchlist')loadWatchlist().catch(report)};

const systemStatus={active:false,mode:null,checking:false,failures:0};
function showSystemStatus(mode,{message='',estimatedEnd=''}={}){const offline=mode==='offline';systemStatus.active=true;systemStatus.mode=mode;$('systemStatusView').dataset.mode=mode;$('systemStatusView').classList.remove('hidden');$('systemStatusView').setAttribute('aria-hidden','false');document.body.classList.add('system-status-active');$('systemStatusIcon').textContent=offline?'⌁':'⚙';$('systemStatusTitle').textContent=offline?'İnternet bağlantısı kesildi':'Şu an bakımdayız';$('systemStatusMessage').textContent=message||(offline?'CollectVerse’e bağlanabilmek için internet bağlantını kontrol et.':'Oyunu daha iyi hale getirmek için kısa bir çalışma yapıyoruz.');$('systemStatusText').textContent=offline?'Bağlantının geri gelmesi bekleniyor…':'Planlı bakım çalışması devam ediyor…';const end=estimatedEnd?new Date(estimatedEnd):null;const valid=end&&!Number.isNaN(end.getTime());$('systemStatusEta').classList.toggle('hidden',!valid);if(valid)$('systemStatusEtaText').textContent=end.toLocaleString('tr-TR',{day:'2-digit',month:'long',hour:'2-digit',minute:'2-digit',timeZone:'Europe/Istanbul'})}
function hideSystemStatus(){const wasActive=systemStatus.active;systemStatus.active=false;systemStatus.mode=null;$('systemStatusView').classList.add('hidden');$('systemStatusView').setAttribute('aria-hidden','true');document.body.classList.remove('system-status-active');$('systemStatusEta').classList.add('hidden');return wasActive}
async function isAdminSession(){const {data:{session}}=await supabase.auth.getSession();if(!session)return false;const {data,error}=await supabase.rpc('is_collectverse_admin');return !error&&data===true}
async function checkSystemStatus(){if(systemStatus.checking)return systemStatus.active;systemStatus.checking=true;try{if(!navigator.onLine){systemStatus.failures=3;showSystemStatus('offline');return true}const request=supabase.from('app_settings').select('value').eq('key','maintenance').maybeSingle();const timeout=new Promise((_,reject)=>setTimeout(()=>reject(new Error('STATUS_TIMEOUT')),7000));const {data,error}=await Promise.race([request,timeout]);if(error)throw error;systemStatus.failures=0;const setting=data?.value||{};if(setting.enabled===true&&!(await isAdminSession())){showSystemStatus('maintenance',{message:setting.message,estimatedEnd:setting.estimated_end});return true}const restored=hideSystemStatus();if(restored&&state.session)await loadGame();return false}catch(error){systemStatus.failures+=1;if(systemStatus.failures>=3)showSystemStatus('offline',{message:'Oyun sunucusuna ulaşılamıyor. İnternet bağlantını kontrol edip yeniden dene.'});return systemStatus.active}finally{systemStatus.checking=false}}

function bind(){
  qa('[data-auth-tab]').forEach(button=>button.addEventListener('click',()=>setAuthTab(button.dataset.authTab)));
  qa('[data-route]').forEach(button=>button.addEventListener('click',event=>{event.preventDefault();routeTo(button.dataset.route)}));
  $('loginForm').addEventListener('submit',login);$('registerForm').addEventListener('submit',register);$('logoutBtn').addEventListener('click',logout);
  $('menuBtn').addEventListener('click',()=>document.querySelector('.app').classList.toggle('menu-open'));$('coreButton').addEventListener('click',clickCore);
  for(const id of ['cardSearch','rarityFilter','setFilter','ownedOnly'])$(id).addEventListener('input',renderCollection);
  $('fusionForm').addEventListener('submit',event=>fuseCards(event).catch(report));$('refreshScoreboardBtn').addEventListener('click',()=>loadScoreboard().catch(report));
  $('refreshMarketBtn').addEventListener('click',()=>loadMarket().catch(report));$('refreshTradesBtn').addEventListener('click',()=>loadTrades().catch(report));
  $('findTradePlayerBtn').addEventListener('click',()=>findTradePlayer().catch(report));$('tradeForm').addEventListener('submit',event=>createTrade(event).catch(report));
  $('systemStatusRetryBtn').addEventListener('click',()=>{systemStatus.failures=0;$('systemStatusText').textContent='Bağlantı kontrol ediliyor…';checkSystemStatus()});
  qa('[data-close-dialog]').forEach(button=>button.addEventListener('click',()=>button.closest('dialog').close()));
  $('goldForm').addEventListener('submit',event=>{event.preventDefault();marketRpc('convert_energy_to_gold',{p_gold:Number($('goldAmount').value)},'Gold hesabına eklendi.',event.currentTarget.querySelector('[type="submit"]')).catch(report)});
  $('fixedForm').addEventListener('submit',event=>{event.preventDefault();marketRpc('create_fixed_listing',{p_player_card:$('fixedCopy').value,p_price:Number($('fixedPrice').value)},'İlan yayımlandı.',event.currentTarget.querySelector('[type="submit"]')).catch(report)});
  $('auctionForm').addEventListener('submit',event=>{event.preventDefault();marketRpc('create_auction_listing',{p_player_card:$('auctionCopy').value,p_base_price:Number($('auctionPrice').value),p_duration_days:Number($('auctionDays').value)},'Açık artırma başladı.',event.currentTarget.querySelector('[type="submit"]')).catch(report)});
  $('buybackForm').addEventListener('submit',event=>{event.preventDefault();const copy=$('buybackCopy').value;if(!copy||!confirm('Bu kart kalıcı olarak sisteme satılsın mı?'))return;marketRpc('sell_card_to_system',{p_player_card:copy},'Kart sisteme satıldı.',event.currentTarget.querySelector('[type="submit"]')).catch(report)});
  document.body.addEventListener('click',event=>{
    const card=event.target.closest('[data-card]');const player=event.target.closest('[data-player]');const pack=event.target.closest('[data-pack]');const upgrade=event.target.closest('[data-upgrade]');
    const buy=event.target.closest('[data-buy-listing]');const bid=event.target.closest('[data-bid-listing]');const cancel=event.target.closest('[data-cancel-listing]');
    const tradeAccept=event.target.closest('[data-trade-accept]');const tradeDecline=event.target.closest('[data-trade-decline]');const tradeCancel=event.target.closest('[data-trade-cancel]');
    if(card)showCard(card.dataset.card);if(player)openPlayer(player.dataset.player).catch(report);if(pack)openPack(pack.dataset.pack,pack);if(upgrade)buyUpgrade(upgrade.dataset.upgrade);
    if(buy)marketRpc('buy_market_listing',{p_listing:buy.dataset.buyListing},'Kart satın alındı.',buy).catch(report);
    if(bid){const amount=Number(q(`[data-bid-value="${bid.dataset.bidListing}"]`)?.value);marketRpc('place_auction_bid',{p_listing:bid.dataset.bidListing,p_amount:amount},'Teklifin kaydedildi.',bid).catch(report)}
    if(cancel)marketRpc('cancel_market_listing',{p_listing:cancel.dataset.cancelListing},'İlan iptal edildi.',cancel).catch(report);
    if(tradeAccept)tradeAction('accept_trade_offer',tradeAccept.dataset.tradeAccept,null,'Takas tamamlandı.',tradeAccept).catch(report);
    if(tradeDecline)tradeAction('close_trade_offer',tradeDecline.dataset.tradeDecline,'decline','Takas reddedildi.',tradeDecline).catch(report);
    if(tradeCancel)tradeAction('close_trade_offer',tradeCancel.dataset.tradeCancel,'cancel','Takas iptal edildi.',tradeCancel).catch(report)
  });
  window.addEventListener('offline',()=>showSystemStatus('offline'));window.addEventListener('online',()=>checkSystemStatus());window.addEventListener('beforeunload',()=>flushClicks())
}
async function applySession(session){state.session=session;if(!session){state.channels.forEach(channel=>supabase?.removeChannel(channel));state.channels=[];$('gameView').classList.add('hidden');$('authView').classList.remove('hidden');hideBootSplash();return}$('authView').classList.add('hidden');$('gameView').classList.remove('hidden');hideBootSplash();await loadGame();loadNotifications().catch(report);routeTo(location.hash.slice(1)||'home')}
async function boot(){bind();if(!configured){$('authView').classList.remove('hidden');hideBootSplash();notify('Supabase bağlantısı yapılandırılmamış.','error');return}const {data,error}=await supabase.auth.getSession();if(error)throw error;state.session=data.session;const blocked=await checkSystemStatus();if(!blocked)await applySession(data.session);else hideBootSplash();supabase.auth.onAuthStateChange(async(_event,session)=>{state.session=session;if(!(await checkSystemStatus()))await applySession(session)});setInterval(()=>{flushClicks();if(state.session&&!systemStatus.active)renderHome()},1000);setInterval(()=>checkSystemStatus().catch(report),10000);setInterval(()=>state.session&&!systemStatus.active&&refreshProfile().catch(report),30000)}
boot().catch(error=>{$('authView').classList.remove('hidden');hideBootSplash();report(error)});
})();
